import{_ as t,o,c as a,a0 as r}from"./chunks/framework.jwovEGr5.js";const g=JSON.parse('{"title":"What \\"Delete\\" Really Does","description":"","frontmatter":{},"headers":[],"relativePath":"reference/soft-delete.md","filePath":"reference/soft-delete.md"}'),n={name:"reference/soft-delete.md"};function i(s,e,l,h,d,c){return o(),a("div",null,[...e[0]||(e[0]=[r('<h1 id="what-delete-really-does" tabindex="-1">What &quot;Delete&quot; Really Does <a class="header-anchor" href="#what-delete-really-does" aria-label="Permalink to &quot;What &quot;Delete&quot; Really Does&quot;">​</a></h1><p>If you&#39;ve ever deleted something and felt a jolt of panic — <em>did I just lose all that data?</em> — this page is for you. In the Kingshot Event Tracker, <strong>deleting almost never means &quot;gone forever.&quot;</strong> Most deletes are reversible.</p><h2 id="soft-delete-the-safety-net" tabindex="-1">Soft delete: the safety net <a class="header-anchor" href="#soft-delete-the-safety-net" aria-label="Permalink to &quot;Soft delete: the safety net&quot;">​</a></h2><p>When you delete a player, event, import, alliance, or kingdom, the app performs a <strong>soft delete</strong>. That means the item is:</p><ul><li><strong>Hidden</strong> from the normal lists and pages, so it&#39;s out of your way, but</li><li><strong>Kept</strong> behind the scenes, in the <strong>Recycle Bin</strong>, where it can be brought back.</li></ul><p>So a delete is really more like &quot;move to the bin&quot; than &quot;shred.&quot; The data is still there until someone deliberately removes it for good.</p><h2 id="the-recycle-bin" tabindex="-1">The Recycle Bin <a class="header-anchor" href="#the-recycle-bin" aria-label="Permalink to &quot;The Recycle Bin&quot;">​</a></h2><p>The Recycle Bin is where soft‑deleted items wait. From there, someone with the right permission can:</p><ul><li><strong>Restore</strong> an item — putting it back where it was, as if it hadn&#39;t been deleted, or</li><li><strong>Purge</strong> an item — permanently removing it.</li></ul><p>Who can do what:</p><ul><li><strong>Viewing and restoring</strong> the bin is available to senior roles (Supreme Admin, King, and Alliance Leader, within their scope).</li><li><strong>Purging</strong> — the permanent removal — is limited to the most senior roles (Supreme Admin and King).</li><li><strong>Lower roles</strong> (like Co‑Leaders) who can&#39;t restore directly can file a <strong>restore request</strong> for an admin to approve. Restore requests are covered in a later section.</li></ul><h2 id="purge-the-one-that-s-forever" tabindex="-1">Purge: the one that&#39;s forever <a class="header-anchor" href="#purge-the-one-that-s-forever" aria-label="Permalink to &quot;Purge: the one that&#39;s forever&quot;">​</a></h2><p><strong>Purging is the only action that truly destroys data</strong>, and it cannot be undone. That&#39;s why it&#39;s restricted to senior roles and comes with a warning. Treat purge as a rare, deliberate act — cleaning out things you&#39;re certain will never be needed again.</p><p>If you&#39;re not sure, <strong>don&#39;t purge</strong> — just leave the item in the bin. It isn&#39;t hurting anything there.</p><h2 id="undoing-an-import-is-a-bit-different" tabindex="-1">Undoing an import is a bit different <a class="header-anchor" href="#undoing-an-import-is-a-bit-different" aria-label="Permalink to &quot;Undoing an import is a bit different&quot;">​</a></h2><p>Screenshot and spreadsheet <strong>imports</strong> have their own kind of undo, called a <strong>rollback</strong>. If you applied an import and then realize it was wrong, rolling it back removes the results that import created — putting your data back the way it was. The import itself can also be restored from the bin and reviewed again. The full import undo story (delete → rollback → restore → re‑apply) is covered in the imports section.</p><h2 id="so-before-you-panic" tabindex="-1">So, before you panic <a class="header-anchor" href="#so-before-you-panic" aria-label="Permalink to &quot;So, before you panic&quot;">​</a></h2><p>If data seems to have vanished, run through this quick checklist:</p><ol><li><strong>Did someone delete it?</strong> Check the Recycle Bin — it may be sitting there, ready to restore.</li><li><strong>Are you in the right <a href="./../getting-started/glossary.html#context-context-banner">context</a>?</strong> Data is scoped to your current kingdom/alliance; the item might just be out of your current view.</li><li><strong>Was an import rolled back?</strong> Its results may have been undone on purpose.</li><li><strong>Is an event instance locked?</strong> Locked instances hide the ability to change results, which can look like missing data.</li></ol><p>Nine times out of ten, the data isn&#39;t gone — it&#39;s in the bin, out of scope, or intentionally undone.</p><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./../getting-started/glossary.html#deleting--recovering">Glossary: soft delete, Recycle Bin, purge, rollback</a></li><li><a href="./../roles/protection-rules.html">Safety Rules You&#39;ll Run Into</a></li><li><a href="./../getting-started/access-denied.html">&quot;You don&#39;t have access&quot;</a></li></ul>',22)])])}const p=t(n,[["render",i]]);export{g as __pageData,p as default};
